import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';

const Cart = () => {
  const { cartItems, removeFromCart, updateQty, totalPrice } = useCart();
  const navigate = useNavigate();

  if (cartItems.length === 0) {
    return (
      <div style={{ textAlign: 'center', marginTop: '60px' }}>
        <h2>🛒 Your cart is empty</h2>
        <button onClick={() => navigate('/')} style={styles.btn}>
          Shop Now
        </button>
      </div>
    );
  }

  return (
    <div style={{ padding: '30px', maxWidth: '800px', margin: '0 auto' }}>
      <h2>🛒 Your Cart</h2>
      {cartItems.map((item) => (
        <div key={item._id} style={styles.item}>
          <img src={item.image} alt={item.name} style={styles.img} />
          <div style={{ flex: 1 }}>
            <h3>{item.name}</h3>
            <p style={{ color: '#e94560' }}>${item.price}</p>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <input
              type="number" min="1" value={item.quantity}
              onChange={(e) => updateQty(item._id, Number(e.target.value))}
              style={styles.qtyInput}
            />
            <button
              onClick={() => removeFromCart(item._id)}
              style={styles.removeBtn}
            >
              ✕
            </button>
          </div>
        </div>
      ))}
      <div style={styles.summary}>
        <h3>Total: <span style={{ color: '#e94560' }}>${totalPrice.toFixed(2)}</span></h3>
        <button onClick={() => navigate('/checkout')} style={styles.btn}>
          Proceed to Checkout →
        </button>
      </div>
    </div>
  );
};

const styles = {
  item: { display: 'flex', alignItems: 'center', gap: '16px', padding: '16px', border: '1px solid #eee', borderRadius: '10px', marginBottom: '12px', background: '#fff' },
  img: { width: '80px', height: '80px', objectFit: 'cover', borderRadius: '8px' },
  qtyInput: { width: '60px', padding: '6px', borderRadius: '6px', border: '1px solid #ddd', textAlign: 'center' },
  removeBtn: { background: '#ff4444', color: '#fff', border: 'none', borderRadius: '6px', padding: '6px 10px', cursor: 'pointer' },
  summary: { textAlign: 'right', marginTop: '20px' },
  btn: { padding: '12px 28px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '8px', fontSize: '16px', cursor: 'pointer', marginTop: '10px' },
};

export default Cart;
